import Header from './components/Header.js';
import Button from './components/Button.js';
import './App.css';
import { useNavigate } from "react-router-dom";
import React, { useEffect, useState } from 'react';
import axios from 'axios';

function QueryPage() {
  const [data, setData] = useState({});
  const [loading, setLoading] = useState(true);

  const navigate = useNavigate();
  const handleClick = () => {
    navigate("/"); // Navigate to the Home page
  };

  // Fetch data from the backend
  useEffect(() => {
    axios.get('http://localhost:5000/api/data') // Adjust to match your backend URL
      .then(response => {
        console.log(response.data); // Log the result here
        setData(response.data); // Assuming response.data is an object with table names as keys
        setLoading(false);
      })
      .catch(error => {
        console.error('Error fetching data:', error);
        setLoading(false);
      });
  }, []);

  return (
    <div className="App">
      <Header />
      <div>
        <h1>Database Tables</h1>
        {loading ? (
          <p>Loading...</p>
        ) : (
          Object.keys(data).length === 0 ? (
            <p>No data available.</p>
          ) : (
            // Iterate over each table in the data object
            Object.keys(data).map((tableName, index) => (
              <div key={index} className="table-section">
                <h2>{tableName}</h2>
                <ul>
                  {data[tableName].length === 0 ? (
                    <li>No records found.</li>
                  ) : (
                    data[tableName].map((row, rowIndex) => (
                      <li key={rowIndex}>
                        {row.join(' - ')} {/* Adjust this based on row data structure */}
                      </li>
                    ))
                  )}
                </ul>
              </div>
            ))
          )
        )}
      </div>
      <Button
        style={{
          position: 'absolute',
          bottom: '30px',
          left: '30px',
        }}
        text="Home Page"
        onClick={handleClick}
      />
    </div>
  );
}

export default QueryPage;
